query:
-- Corrigir cardType baseado no overall
UPDATE players SET cardType = 'gold' WHERE overall >= 75;
UPDATE players SET cardType = 'silver' WHERE overall >= 65 AND overall < 75;
UPDATE players SET cardType = 'bronze' WHERE overall < 65;
-- Verificar resultado
SELECT cardType, MIN(overall) as min_overall, MAX(overall) as max_overall, COUNT(*) as total
FROM players GROUP BY cardType ORDER BY min_overall DESC;

